const yaml = require('js-yaml');
const doc = yaml.load($input.item.json.stdout || '') || { items: [] };
const now = Date.now();
const items = (doc.items || []).map(i => {
  const due = new Date(i.next_due).getTime();
  const daysUntil = Math.floor((due - now) / 86400000);
  return { ...i, daysUntil };
});
const overdue = items.filter(i => i.daysUntil < 0);
const dueSoon = items.filter(i => i.daysUntil >= 0 && i.daysUntil <= 7);
if (overdue.length === 0 && dueSoon.length === 0) return [];
const priority = overdue.length > 0 ? 'P0' : 'P1';
const lines = [
  ...overdue.map(i => `• OVERDUE ${Math.abs(i.daysUntil)}d: ${i.label}`),
  ...dueSoon.map(i => `• ${i.daysUntil}d: ${i.label}`)
];
return [{ json: {
  priority,
  source: 'due-soon-watch',
  message: `${overdue.length} overdue · ${dueSoon.length} due ≤7d:\n${lines.join('\n')}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/maintain/calendar'
}}];
